// ── Parse payload từ BE ──
// BE gửi: { provider, model, prompt, context }
const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

if (!body.prompt) {
  throw new Error('Payload thiếu trường prompt.');
}

return [{
  json: {
    provider:   body.provider ?? 'N8n',
    model:      body.model    ?? 'llama-3.3-70b-versatile',
    userPrompt: body.prompt,
    context:    body.context  ?? ''
  }
}];

// ── Parse LLM response ──
const response = $input.first().json;

const rawContent =
  response?.output ??
  response?.choices?.[0]?.message?.content ??
  null;

if (!rawContent) {
  throw new Error('LLM trả về response rỗng.');
}

// Cleanup markdown fences
let cleaned = String(rawContent).trim().replace(/^\uFEFF/, '');
const fencedMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
if (fencedMatch?.[1]) {
  cleaned = fencedMatch[1].trim();
} else {
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
}
cleaned = cleaned.replace(/```/g, '').trim();

const firstBrace = cleaned.indexOf('{');
const lastBrace  = cleaned.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
}

cleaned = cleaned.replace(/,\s*([}\]])/g, '$1');

// Fix unescaped control chars
function fixJsonStrings(s) {
  let result = '', inString = false, i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (inString) {
      if (ch === '\\') { result += ch; i++; if (i < s.length) { result += s[i]; i++; } continue; }
      if (ch === '"') { inString = false; result += ch; i++; continue; }
      if (ch === '\n') { result += '\\n'; i++; continue; }
      if (ch === '\r') { result += '\\r'; i++; continue; }
      if (ch === '\t') { result += '\\t'; i++; continue; }
      result += ch; i++;
    } else {
      if (ch === '"') inString = true;
      result += ch; i++;
    }
  }
  return result;
}
cleaned = fixJsonStrings(cleaned);

const ob = (cleaned.match(/{/g)||[]).length, cb = (cleaned.match(/}/g)||[]).length;
const oB = (cleaned.match(/\[/g)||[]).length, cB = (cleaned.match(/\]/g)||[]).length;
for (let i = 0; i < oB - cB; i++) cleaned += ']';
for (let i = 0; i < ob - cb; i++) cleaned += '}';

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: AI không trả JSON, wrap raw text
  parsed = {
    summaryVi: rawContent.substring(0, 500),
    possibleCauses: ['Không thể parse response từ AI'],
    suggestedNextActions: ['Kiểm tra lại request và response của test case'],
    confidence: 'low',
  };
}

// Validate required fields
if (!parsed.summaryVi) {
  parsed.summaryVi = rawContent.substring(0, 300);
}

return [{
  json: {
    summaryVi:            String(parsed.summaryVi ?? ''),
    possibleCauses:       Array.isArray(parsed.possibleCauses)       ? parsed.possibleCauses       : [],
    suggestedNextActions: Array.isArray(parsed.suggestedNextActions) ? parsed.suggestedNextActions : [],
    confidence:           String(parsed.confidence ?? 'medium'),
    model:                String(parsed.model      ?? 'llama-3.3-70b-versatile'),
    tokensUsed:           Number(parsed.tokensUsed ?? 0)
  }
}];

// Parse LLM response
const response = $input.first().json;

const rawContent =
  response?.output ??
  response?.choices?.[0]?.message?.content ??
  null;

if (!rawContent) {
  throw new Error('LLM returned empty response. Keys: ' + Object.keys(response || {}).join(', '));
}

// Cleanup markdown fences
