const fencedMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
if (fencedMatch?.[1]) {
  cleaned = fencedMatch[1].trim();
} else {
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
}
cleaned = cleaned.replace(/```/g, '').trim();

const firstBrace = cleaned.indexOf('{');
const lastBrace  = cleaned.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  cleaned = cleaned.slice(firstBrace, lastBrace + 1);
}

cleaned = cleaned.replace(/,\s*([}\]])/g, '$1');

function fixJsonStrings(s) {
  let result = '', inString = false, i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (inString) {
      if (ch === '\\') { result += ch; i++; if (i < s.length) { result += s[i]; i++; } continue; }
      if (ch === '"') { inString = false; result += ch; i++; continue; }
      if (ch === '\n') { result += '\\n'; i++; continue; }
      if (ch === '\r') { result += '\\r'; i++; continue; }
      if (ch === '\t') { result += '\\t'; i++; continue; }
      result += ch; i++;
    } else {
      if (ch === '"') inString = true;
      result += ch; i++;
    }
  }
  return result;
}
cleaned = fixJsonStrings(cleaned);

cleaned = cleaned.replace(/,\s*$/, '');
const ob = (cleaned.match(/{/g)||[]).length, cb = (cleaned.match(/}/g)||[]).length;
const oB = (cleaned.match(/\[/g)||[]).length, cB = (cleaned.match(/\]/g)||[]).length;
for (let i = 0; i < oB - cB; i++) cleaned += ']';
for (let i = 0; i < ob - cb; i++) cleaned += '}';

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Cannot parse JSON from LLM. Error: ' + e.message + '\nRaw (800): ' + cleaned.substring(0, 800));
}

const requirements = parsed?.requirements;
if (!Array.isArray(requirements) || requirements.length === 0) {
  throw new Error('LLM response missing requirements array or empty.');
}

const clarificationQuestions = Array.isArray(parsed?.clarificationQuestions)
  ? parsed.clarificationQuestions
  : [];

const validTypes = ['functional', 'non-functional', 'security', 'performance', 'constraint'];
const asJsonArrayString = (v, def) => {
  if (v === null || v === undefined) return def;
  if (typeof v === 'string') {
    const s = v.trim();
    if (!s) return def;
    try { JSON.parse(s); return s; } catch { return JSON.stringify([s]); }
  }
  if (Array.isArray(v)) return JSON.stringify(v);
  return def;
};

requirements.forEach((r, i) => {
  if (!r.requirementCode) r.requirementCode = `REQ-${String(i + 1).padStart(3, '0')}`;
  if (!r.title) throw new Error(`Requirement index ${i} missing title.`);
  if (!r.description) r.description = r.title;
  r.type = validTypes.includes(String(r.type).toLowerCase())
    ? String(r.type).toLowerCase()
    : 'functional';
  r.testableConstraints = asJsonArrayString(r.testableConstraints, '[]');
  r.assumptions = asJsonArrayString(r.assumptions, '[]');
  r.ambiguities = asJsonArrayString(r.ambiguities, '[]');
  r.confidenceScore = typeof r.confidenceScore === 'number'
    ? Math.min(1, Math.max(0, r.confidenceScore))
    : 0.7;
  r.mappedEndpointPath = r.mappedEndpointPath ?? null;
});

clarificationQuestions.forEach((q, i) => {
  if (!q.requirementCode) throw new Error(`ClarificationQuestion index ${i} missing requirementCode.`);
  if (!q.question) throw new Error(`ClarificationQuestion index ${i} missing question.`);
  q.ambiguitySource = q.ambiguitySource ?? q.question;
  q.isCritical = q.isCritical === true;
  q.suggestedOptions = asJsonArrayString(q.suggestedOptions, null);
});

return [{
  json: {
    requirements,
    clarificationQuestions,
    model: parsed.model ?? 'llama-3.3-70b-versatile',
    tokensUsed: parsed.tokensUsed ?? 0
  }
}];

