const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

const endpoints = body.endpoints;
if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload must contain non-empty endpoints array.');
}

const promptConfig = body.promptConfig ?? {};
if (!promptConfig.systemPrompt || !String(promptConfig.systemPrompt).trim()) throw new Error('Payload missing promptConfig.systemPrompt from BE.');
if (!promptConfig.taskInstruction || !String(promptConfig.taskInstruction).trim()) throw new Error('Payload missing promptConfig.taskInstruction from BE.');
if (!promptConfig.rules || !String(promptConfig.rules).trim()) throw new Error('Payload missing promptConfig.rules from BE.');
if (!promptConfig.responseFormat || !String(promptConfig.responseFormat).trim()) throw new Error('Payload missing promptConfig.responseFormat from BE.');

const callbackUrl = String(body.callbackUrl ?? '').trim();
if (!callbackUrl) throw new Error('Payload missing callbackUrl from BE.');

const callbackApiKey = String(body.callbackApiKey ?? '').trim();
if (!callbackApiKey) throw new Error('Payload missing callbackApiKey from BE.');

const refinementJobId = String(body.refinementJobId ?? '').trim();
if (!refinementJobId) throw new Error('Payload missing refinementJobId from BE.');

return [{ json: {
  testSuiteId: body.testSuiteId ?? '',
  refinementJobId,
  callbackUrl,
  callbackApiKey,
