}}];

const { testSuiteId, refinementJobId, callbackUrl, callbackApiKey, promptConfig, endpoints, algorithmProfile, srsContext } = $input.first().json;

const promptBlocks = endpoints.map((ep, i) => {
  const combined = String(ep?.prompt?.combinedPrompt || '').trim();
  if (!combined) throw new Error(`Endpoint ${i + 1} (ID=${ep?.endpointId || 'unknown'}) is missing prompt.combinedPrompt from BE.`);
  return `### Endpoint ${i + 1} [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}\n${combined}`;
});

const systemPrompt = String(promptConfig.systemPrompt || '').trim();
const taskInstruction = String(promptConfig.taskInstruction || '').trim();
const rules = String(promptConfig.rules || '').trim();
const responseFormat = String(promptConfig.responseFormat || '').trim();

const enabledFlags = Object.entries(algorithmProfile || {}).filter(([,v]) => v === true).map(([k]) => `- ${k}`);
const algorithmGuidance = enabledFlags.length > 0
  ? ['=== ALGORITHM PROFILE FROM BE (ENABLED FLAGS) ===', enabledFlags.join('\n'), 'Apply these generation strategies while producing scenarios.'].join('\n')
  : ['=== ALGORITHM PROFILE FROM BE (ENABLED FLAGS) ===', '- none', 'Use promptConfig instructions as the primary strategy.'].join('\n');

let srsSection = '';
if (srsContext && (srsContext.content || (Array.isArray(srsContext.requirements) && srsContext.requirements.length > 0))) {
  const parts = [`=== SRS DOCUMENT: ${srsContext.documentTitle || 'Untitled'} ===`];
  if (srsContext.content) parts.push(srsContext.content);
  if (Array.isArray(srsContext.requirements) && srsContext.requirements.length > 0) {
    parts.push('--- REQUIREMENTS ---');
    for (const req of srsContext.requirements) {
      parts.push(`[${req.code}] ${req.title}`);
      if (req.endpointId) parts.push(`EndpointId: ${req.endpointId}`);
      if (req.description) parts.push(String(req.description));
      parts.push('');
    }
  }
  srsSection = parts.join('\n');
}

const userPrompt = [
  taskInstruction,
  algorithmGuidance,
  ...(srsSection ? ['=== SRS REQUIREMENTS (align generated scenarios to these) ===', srsSection] : []),
  '=== BE GENERATED ENDPOINT PROMPTS (PRIMARY INPUT) ===',
  promptBlocks.join('\n\n'),
  rules,
  responseFormat
].join('\n\n');

return [{ json: { testSuiteId, refinementJobId, callbackUrl, callbackApiKey, systemPrompt, userPrompt } }];

const response = $input.first().json;

const rawContent = response?.output ?? response?.choices?.[0]?.message?.content ?? null;
if (!rawContent) {
  return [{ json: { scenarios: [], model: 'unknown', tokensUsed: 0, warning: 'LLM_EMPTY_OR_TERMINATED' } }];
}

