const fencedMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
if (fencedMatch?.[1]) cleaned = fencedMatch[1].trim();
else cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
cleaned = cleaned.replace(/```/g, '').trim();

const firstBrace = cleaned.indexOf('{');
const lastBrace = cleaned.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) cleaned = cleaned.slice(firstBrace, lastBrace + 1);
cleaned = cleaned.replace(/,\s*([}\]])/g, '$1');

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch {
  return [{ json: { scenarios: [], model: 'unknown', tokensUsed: 0, warning: 'LLM_JSON_PARSE_FAILED' } }];
}

const scenarios = Array.isArray(parsed?.scenarios) ? parsed.scenarios : [];
for (let i = 0; i < scenarios.length; i++) {
  const s = scenarios[i] ?? {};
  s.scenarioName = String(s.scenarioName ?? `Scenario ${i + 1}`);
  s.description = String(s.description ?? '');
  s.testType = String(s.testType ?? 'Negative');
  s.priority = String(s.priority ?? 'Medium');
  s.tags = Array.isArray(s.tags) ? s.tags : [];
  s.variables = Array.isArray(s.variables) ? s.variables : [];
  s.coveredRequirementCodes = Array.isArray(s.coveredRequirementCodes) ? s.coveredRequirementCodes.map(String).filter(x => x.trim()) : [];

  s.request = s.request ?? {};
  s.request.httpMethod = String(s.request.httpMethod ?? 'GET');
  s.request.url = String(s.request.url ?? '/');
  s.request.bodyType = String(s.request.bodyType ?? 'None');
  s.request.timeout = Number(s.request.timeout ?? 30000);
  s.request.headers = s.request.headers ?? null;
  s.request.pathParams = s.request.pathParams ?? null;
  s.request.queryParams = s.request.queryParams ?? null;
  if (s.request.body !== null && s.request.body !== undefined && typeof s.request.body !== 'string') s.request.body = JSON.stringify(s.request.body);

  s.expectation = s.expectation ?? {};
  if (!Array.isArray(s.expectation.expectedStatus) || s.expectation.expectedStatus.length === 0 || !s.expectation.expectedStatus.every(x => Number.isInteger(x))) {
    s.expectation.expectedStatus = [400];
  }
  s.expectation.bodyContains = s.expectation.bodyContains ?? null;
  s.expectation.bodyNotContains = s.expectation.bodyNotContains ?? null;
  s.expectation.jsonPathChecks = (s.expectation.jsonPathChecks && typeof s.expectation.jsonPathChecks === 'object' && Object.keys(s.expectation.jsonPathChecks).length > 0) ? s.expectation.jsonPathChecks : null;
}

return [{ json: { scenarios, model: parsed?.model ?? 'unknown', tokensUsed: Number(parsed?.tokensUsed ?? 0) } }];

