const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

if (!body.testSuiteId) throw new Error('Payload missing testSuiteId.');
if (!Array.isArray(body.endpoints) || body.endpoints.length === 0) throw new Error('Payload must contain non-empty endpoints array.');
if (!body.callbackUrl || !String(body.callbackUrl).trim()) throw new Error('Payload missing callbackUrl.');
if (!body.callbackApiKey || !String(body.callbackApiKey).trim()) throw new Error('Payload missing callbackApiKey.');

const promptConfig = body.promptConfig ?? {};
for (const key of ['systemPrompt', 'taskInstruction', 'rules', 'responseFormat']) {
  if (!promptConfig[key] || !String(promptConfig[key]).trim()) {
    throw new Error(`Payload missing promptConfig.${key}.`);
  }
}

return [{ json: {
  testSuiteId: String(body.testSuiteId),
  testSuiteName: String(body.testSuiteName ?? ''),
  specificationId: String(body.specificationId ?? ''),
  callbackUrl: String(body.callbackUrl).trim(),
  callbackApiKey: String(body.callbackApiKey).trim(),
  model: String(body.model || 'llama-3.3-70b-versatile'),
  maxOutputTokens: Number(body.maxOutputTokens || 4096),
  preferJsonObjectResponse: body.preferJsonObjectResponse !== false,
  promptConfig,
  endpoints: body.endpoints,
  endpointBusinessContexts: body.endpointBusinessContexts ?? {},
  globalBusinessRules: String(body.globalBusinessRules ?? ''),
  srsRequirements: Array.isArray(body.srsRequirements) ? body.srsRequirements : []
}}];

const input = $input.first().json;

const truncate = (value, max = 1200) => {
  const text = value === null || value === undefined ? '' : String(value).trim();
  return text.length > max ? text.slice(0, max) : text;
};

const compactJson = (value, max = 1200) => {
  if (value === null || value === undefined) return '';
  try { return truncate(JSON.stringify(value), max); } catch { return truncate(value, max); }
};

const toArray = (value) => Array.isArray(value) ? value : [];

const requirementsByEndpoint = new Map();
for (const req of toArray(input.srsRequirements)) {
  const endpointIds = toArray(req.endpointIds);
  const dependencyEndpointIds = toArray(req.dependencyEndpointIds);
  const brief = {
    id: req.id,
    code: req.code,
    title: truncate(req.title, 220),
    type: req.requirementType,
    effectiveConstraints: truncate(req.effectiveConstraints, 420),
    confidenceScore: req.confidenceScore ?? null,
    relevance: 'direct'
  };
  for (const endpointId of endpointIds) {
    const key = String(endpointId);
    if (!requirementsByEndpoint.has(key)) requirementsByEndpoint.set(key, []);
    requirementsByEndpoint.get(key).push(brief);
  }
  for (const endpointId of dependencyEndpointIds) {
    const key = String(endpointId);
    if (!requirementsByEndpoint.has(key)) requirementsByEndpoint.set(key, []);
    requirementsByEndpoint.get(key).push({ ...brief, relevance: 'dependency-context' });
  }
}

const endpointBlocks = input.endpoints.map((ep, index) => {
  const prompt = ep.prompt ?? {};
  const endpointId = String(ep.endpointId ?? '');
  const block = {
    endpointIndex: index + 1,
    endpointId,
    method: ep.httpMethod ?? 'GET',
    path: ep.path ?? '/',
    operationId: ep.operationId ?? null,
    orderIndex: ep.orderIndex ?? index,
    dependsOnEndpointIds: toArray(ep.dependsOnEndpointIds).map(String),
    reasonCodes: toArray(ep.reasonCodes),
    isAuthRelated: ep.isAuthRelated === true,
    businessContext: truncate(ep.businessContext, 450),
    parameterDetails: toArray(ep.parameterDetails).slice(0, 16),
    parameterSchemas: toArray(ep.parameterSchemaPayloads).slice(0, 1).map(x => truncate(x, 700)),
    responseSchemas: toArray(ep.responseSchemaPayloads).slice(0, 1).map(x => truncate(x, 700)),
    srsRequirements: (requirementsByEndpoint.get(endpointId) ?? []).slice(0, 6),
    generationPrompt: truncate(prompt.combinedPrompt || prompt.observationPrompt || '', 1200)
  };
  return compactJson(block, 4200);
});

const dependencyOrder = input.endpoints.map((ep, i) => ({
  endpointId: String(ep.endpointId ?? ''),
  orderIndex: ep.orderIndex ?? i,
  dependsOnEndpointIds: toArray(ep.dependsOnEndpointIds).map(String),
  method: ep.httpMethod ?? 'GET',
  path: ep.path ?? '/'
}));

const callbackContract = [
  'Return ONLY raw JSON, no markdown.',
  'Top level must be a JSON object with a testCases array.',
  'Each test case must include endpointId, name, description, testType, priority, orderIndex, tags, request, expectation, variables, coveredRequirementIds, traceabilityScore, mappingRationale.',
  'Use only these testType values: HappyPath, Boundary, Negative, Performance, Security.',
  'Use only these priority values: Critical, High, Medium, Low.',
  'request.url must be the API path, not a full host URL.',
  'expectedStatus must use documented response statuses from the endpoint context.',
  'For dependency setup, generate producer test cases before consumers and add variables where a later request needs extracted values.',
  'For unique fields use {{tcUniqueId}}; never invent random suffixes.'
].join('\n');

const systemPrompt = [
  input.promptConfig.systemPrompt,
  'Optimize for fast, compact, valid JSON. Avoid explanations. Do not repeat the input. Generate only executable API test cases.'
].filter(Boolean).join('\n\n');

const userPrompt = [
  input.promptConfig.taskInstruction,
  '=== GENERATION BUDGET ===',
  compactJson({ model: input.model, maxOutputTokens: input.maxOutputTokens, endpointCount: input.endpoints.length }, 300),
  '=== ORDERED ENDPOINT CONTEXT ===',
  endpointBlocks.join('\n'),
  '=== DEPENDENCY ORDER ===',
  compactJson(dependencyOrder, 1800),
  input.globalBusinessRules ? '=== GLOBAL BUSINESS RULES ===\n' + truncate(input.globalBusinessRules, 700) : '',
  '=== RULES FROM BACKEND ===',
  truncate(input.promptConfig.rules, 2400),
  '=== RESPONSE FORMAT FROM BACKEND ===',
  truncate(input.promptConfig.responseFormat, 2200),
  '=== STRICT CALLBACK CONTRACT ===',
  callbackContract
].filter(Boolean).join('\n\n');

return [{ json: { ...input, systemPrompt, userPrompt } }];

const source = $node['Prepare Unified Generation Prompt'].json;
const response = $input.first().json;
const rawContent = response?.output ?? response?.choices?.[0]?.message?.content ?? response?.text ?? '';

function cleanJsonText(value) {
  let cleaned = String(value || '').trim().replace(/^\uFEFF/, '');
  const fencedMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fencedMatch?.[1]) cleaned = fencedMatch[1].trim();
  else cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  cleaned = cleaned.replace(/```/g, '').trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) cleaned = cleaned.slice(firstBrace, lastBrace + 1);
  return cleaned.replace(/,\s*([}\]])/g, '$1').trim();
}

function parseOrNull(value) {
  const cleaned = cleanJsonText(value);
  if (!cleaned) return null;
  try { return JSON.parse(cleaned); } catch { return null; }
}

function asJsonString(value, fallback) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'string') {
    const text = value.trim();
    if (!text) return fallback;
    return text;
  }
  try { return JSON.stringify(value); } catch { return fallback; }
}

function asJsonObjectString(value) { return asJsonString(value, '{}'); }
function asJsonArrayString(value) { return asJsonString(Array.isArray(value) ? value : (value ? [String(value)] : []), '[]'); }
function nullableJson(value) {
  if (value === null || value === undefined || value === '') return null;
  return asJsonString(value, null);
}

const guidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const validTypes = new Set(['HappyPath', 'Boundary', 'Negative', 'Performance', 'Security']);
const validPriorities = new Set(['Critical', 'High', 'Medium', 'Low']);
const endpoints = Array.isArray(source.endpoints) ? source.endpoints : [];
const endpointById = new Map(endpoints.map((ep, i) => [String(ep.endpointId), { ...ep, index: i }]));

function normalizeType(value) {
  const raw = String(value || '').replace(/[\s_-]/g, '').toLowerCase();
  if (raw === 'happypath' || raw === 'success') return 'HappyPath';
  if (raw === 'boundary') return 'Boundary';
  if (raw === 'negative' || raw === 'error') return 'Negative';
  if (raw === 'performance') return 'Performance';
  if (raw === 'security') return 'Security';
  return 'HappyPath';
}

function normalizePriority(value) {
  const raw = String(value || '').toLowerCase();
  if (raw === 'critical') return 'Critical';
  if (raw === 'high') return 'High';
  if (raw === 'low') return 'Low';
  return 'Medium';
}

function normalizeExpectedStatus(value, testType) {
  const values = Array.isArray(value) ? value : [value];
  const parsed = values.map(x => Number.parseInt(String(x), 10)).filter(x => Number.isInteger(x) && x >= 100 && x <= 599);
  if (parsed.length > 0) return [...new Set(parsed)];
  return testType === 'HappyPath' ? [200] : [400];
}

function normalizeTags(value, testType, fallback = false) {
  const tags = Array.isArray(value) ? value.map(String) : String(value || '').split(',');
  const cleaned = tags.map(x => x.trim()).filter(Boolean);
  const typeTag = testType === 'HappyPath' ? 'happy-path' : testType.toLowerCase();
  for (const tag of [typeTag, 'auto-generated', 'llm-suggested']) {
    if (!cleaned.some(x => x.toLowerCase() === tag.toLowerCase())) cleaned.push(tag);
  }
  if (fallback && !cleaned.includes('fallback')) cleaned.push('fallback');
  return JSON.stringify(cleaned);
}

function normalizeVariables(value) {
  if (!Array.isArray(value)) return [];
  return value.map(v => ({
    variableName: String(v?.variableName ?? v?.name ?? '').trim(),
    extractFrom: String(v?.extractFrom ?? 'ResponseBody').trim(),
    jsonPath: v?.jsonPath ?? null,
    headerName: v?.headerName ?? null,
    regex: v?.regex ?? null,
    defaultValue: v?.defaultValue ?? null
  })).filter(v => v.variableName && v.extractFrom);
}

function normalizeCoveredRequirementIds(value) {
  if (!Array.isArray(value)) return [];
  return value.map(String).filter(x => guidRegex.test(x));
}

function normalizeTestCase(tc, index, fallback = false) {
  const endpointId = String(tc?.endpointId ?? endpoints[index]?.endpointId ?? endpoints[0]?.endpointId ?? '');
  const endpoint = endpointById.get(endpointId) ?? { ...(endpoints[index] ?? endpoints[0] ?? {}), index };
  const testType = normalizeType(tc?.testType);
  const priority = normalizePriority(tc?.priority);
  const request = tc?.request ?? {};
  const expectation = tc?.expectation ?? {};
  const method = String(request.httpMethod ?? endpoint.httpMethod ?? 'GET').toUpperCase();
  const url = String(request.url ?? endpoint.path ?? '/');
  const bodyValue = request.body;
  const timeout = Number(request.timeout ?? 30000);
  const traceabilityScore = Number(tc?.traceabilityScore ?? (fallback ? 0.45 : 0.9));

  return {
    endpointId,
    name: String(tc?.name ?? `${method} ${url} ${testType}`).slice(0, 180),
    description: String(tc?.description ?? (fallback ? 'Fallback test case generated when the LLM response could not be parsed.' : '')).slice(0, 500),
    testType: validTypes.has(testType) ? testType : 'HappyPath',
    priority: validPriorities.has(priority) ? priority : 'Medium',
    orderIndex: Number.isInteger(Number(tc?.orderIndex)) ? Number(tc.orderIndex) : index,
    tags: normalizeTags(tc?.tags, testType, fallback),
    request: {
      httpMethod: method,
      url,
      headers: asJsonObjectString(request.headers),
      pathParams: asJsonObjectString(request.pathParams),
      queryParams: asJsonObjectString(request.queryParams),
      bodyType: String(request.bodyType ?? (bodyValue ? 'JSON' : 'None')),
      body: bodyValue && typeof bodyValue === 'object' ? JSON.stringify(bodyValue) : (bodyValue ?? null),
      timeout: Number.isFinite(timeout) && timeout > 0 ? timeout : 30000
    },
    expectation: {
      expectedStatus: normalizeExpectedStatus(expectation.expectedStatus, testType),
      responseSchema: nullableJson(expectation.responseSchema),
      headerChecks: asJsonObjectString(expectation.headerChecks),
      bodyContains: asJsonArrayString(expectation.bodyContains),
      bodyNotContains: asJsonArrayString(expectation.bodyNotContains),
      jsonPathChecks: asJsonObjectString(expectation.jsonPathChecks),
      maxResponseTime: expectation.maxResponseTime ?? null
    },
    variables: normalizeVariables(tc?.variables),
    coveredRequirementIds: normalizeCoveredRequirementIds(tc?.coveredRequirementIds),
    traceabilityScore: Math.max(0, Math.min(1, Number.isFinite(traceabilityScore) ? traceabilityScore : 0.9)),
    mappingRationale: String(tc?.mappingRationale ?? (fallback ? 'Generated by n8n fallback because the LLM output was empty or invalid JSON.' : 'Mapped by LLM from endpoint and SRS context.')).slice(0, 500)
  };
}

function fallbackCases() {
  return endpoints.map((ep, index) => normalizeTestCase({
    endpointId: ep.endpointId,
    name: `${String(ep.httpMethod ?? 'GET').toUpperCase()} ${ep.path ?? '/'} happy path`,
    description: 'Fallback happy-path smoke test for this endpoint.',
    testType: 'HappyPath',
    priority: ep.isAuthRelated ? 'High' : 'Medium',
    orderIndex: ep.orderIndex ?? index,
    tags: ['happy-path'],
    request: { httpMethod: ep.httpMethod ?? 'GET', url: ep.path ?? '/', bodyType: 'None', timeout: 30000 },
    expectation: { expectedStatus: [200] },
    variables: []
  }, index, true));
}

const parsed = parseOrNull(rawContent);
const rawCases = Array.isArray(parsed?.testCases) ? parsed.testCases : (Array.isArray(parsed?.tests) ? parsed.tests : []);
const testCases = rawCases.length > 0 ? rawCases.map((tc, i) => normalizeTestCase(tc, i, false)) : fallbackCases();

return [{ json: { testCases, model: parsed?.model ?? source.model, tokensUsed: Number(parsed?.tokensUsed ?? 0), fallbackUsed: rawCases.length === 0 } }];
